Consultas sobre una tabla.answer:
SELECT nombre
    FROM fabricante
    ORDER BY nombre ASC;

SELECT nombre
    FROM fabricante
    ORDER BY nombre DESC;

SELECT nombre
    FROM producto
    ORDER BY nombre ASC, precio DESC;

SELECT *
    FROM fabricante
    LIMIT 5;

SELECT *
    FROM fabricante
    LIMIT 3, 2;

SELECT nombre
    FROM producto
    WHERE id_fabricante = 2;

SELECT nombre
    FROM producto
    WHERE precio <= 120;

SELECT nombre
    FROM producto
    WHERE precio >= 400;

SELECT nombre
    FROM producto
    WHERE NOT (precio >= 400);

SELECT nombre
    FROM producto
    WHERE precio >= 80 AND precio <= 300;

SELECT nombre
    FROM producto
    WHERE precio BETWEEN 60 AND 200;

SELECT p.nombre
    FROM producto p
    WHERE p.precio > 200 AND p.id_fabricante = 6;

SELECT p.nombre
    FROM producto p
    WHERE p.id_fabricante = 1 OR p.id_fabricante = 3 OR p.id_fabricante = 5;

SELECT p.nombre
    FROM producto p
    WHERE p.id_fabricante IN (1, 3, 5);

SELECT nombre
    FROM fabricante
    WHERE nombre LIKE "s%";

SELECT nombre
    FROM fabricante
    WHERE nombre LIKE "%e";

SELECT nombre
    FROM fabricante
    WHERE nombre LIKE "%w%";

SELECT nombre
    FROM fabricante
    WHERE LENGTH(nombre) = 4;

SELECT nombre
    FROM producto
    WHERE nombre LIKE "%Portátil%";

SELECT nombre
    FROM producto
    WHERE nombre LIKE "%Monitor%" AND precio < 215;

Consultas multitabla (Composición intern.answer:
SELECT p.nombre AS 'Nombre producto', p.precio, f.nombre AS 'Nombre Fabricante'
    FROM producto p INNER JOIN fabricante f ON p.id_fabricante = f.id
    ORDER BY f.nombre ASC;

SELECT p.nombre
    FROM producto p INNER JOIN fabricante f ON p.id_fabricante = f.id
    WHERE f.nombre = 'Lenovo';

SELECT p.nombre
    FROM producto p INNER JOIN fabricante f ON p.id_fabricante = f.id
    WHERE f.nombre = 'Crucial' AND p.precio > 200;

SELECT p.nombre
    FROM producto p INNER JOIN fabricante f ON p.id_fabricante = f.id
    WHERE f.nombre = 'Asus' OR f.nombre = 'Hewlett-Packard' OR f.nombre = 'Seagate';

SELECT p.nombre
    FROM producto p INNER JOIN fabricante f ON p.id_fabricante = f.id
    WHERE f.nombre IN ('Asus', 'Hewlett-Packard', 'Seagate');

SELECT p.nombre, p.precio
    FROM producto p INNER JOIN fabricante f ON p.id_fabricante = f.id
    WHERE f.nombre LIKE '%e';

SELECT p.nombre, p.precio
    FROM producto p INNER JOIN fabricante f ON p.id_fabricante = f.id
    WHERE f.nombre LIKE '%w%';

Consultas multitabla (Composición extern.answer:
SELECT f.nombre
    FROM fabricante f LEFT JOIN producto p ON p.id_fabricante = f.id
    WHERE p.id_fabricante IS NULL;

Consultas resumen.answer:
SELECT COUNT(*) AS 'Cantidad de productos ASUS'
    FROM producto p INNER JOIN fabricante f ON p.id_fabricante = f.id
    WHERE f.nombre = 'Asus';

SELECT AVG(p.precio) AS 'Promedio de precio - ASUS'
    FROM producto p INNER JOIN fabricante f ON p.id_fabricante = f.id
    WHERE f.nombre = 'Asus';

SELECT MIN(p.precio) AS 'Precio mas barato - ASUS'
    FROM producto p INNER JOIN fabricante f ON p.id_fabricante = f.id
    WHERE f.nombre = 'Asus';

SELECT MAX(p.precio) AS 'Precio mas caro - ASUS'
    FROM producto p INNER JOIN fabricante f ON p.id_fabricante = f.id
    WHERE f.nombre = 'Asus';

SELECT SUM(p.precio) AS 'Suma precios - ASUS'
    FROM producto p INNER JOIN fabricante f ON p.id_fabricante = f.id
    WHERE f.nombre = 'Asus';

SELECT MAX(p.precio) AS Máximo, MIN(p.precio) AS Mínimo, AVG(p.precio) AS Promedio, COUNT(*) AS 'Cantidad de productos'
    FROM producto p INNER JOIN fabricante f ON p.id_fabricante = f.id
    WHERE f.nombre = 'Crucial';

SELECT COUNT(*) AS 'Cantidad de productos con Precio >= 180€'
    FROM producto
    WHERE precio >= 180;

SELECT p.id_fabricante, AVG(p.precio) AS 'Promedio'
    FROM producto p
    GROUP BY p.id_fabricante;

SELECT f.nombre, AVG(p.precio) AS 'Promedio'
    FROM producto p INNER JOIN fabricante f ON p.id_fabricante = f.id
    GROUP BY f.nombre;
